void ProcessDialogEvent(){	ref NPChar;	aref Link, NextDiag;	DeleteAttribute(&Dialog, "Links");	makeref(NPChar, CharacterRef);	makearef(Link, Dialog.Links);	makearef(NextDiag, NPChar.Dialog);	switch (Dialog.CurrentNode)	{		case "first time":			dialog.text = StringFromKey("OldSmuggler_1");			link.l1 = StringFromKey("OldSmuggler_2");			link.l1.go = "0";		break;		case "0":			dialog.text = StringFromKey("OldSmuggler_3");			link.l1 = "...";			link.l1.go = "exit";			AddDialogExitQuest("FL3_s6");			NextDiag.TempNode = "1";		break;		case "1":			dialog.text = "...";			link.l1 = StringFromKey("OldSmuggler_4");			link.l1.go = "2";		break;		case "2":			dialog.text = StringFromKey("OldSmuggler_5");			link.l1 = StringFromKey("OldSmuggler_6");			link.l1.go = "3";		break;		case "3":			dialog.text = StringFromKey("OldSmuggler_7");			link.l1 = StringFromKey("OldSmuggler_8");			link.l1.go = "4";		break;		case "4":			dialog.text = StringFromKey("OldSmuggler_9");			link.l1 = StringFromKey("OldSmuggler_10");			link.l1.go = "5";		break;		case "5":			dialog.text = StringFromKey("OldSmuggler_11");			link.l1 = StringFromKey("OldSmuggler_12");			link.l1.go = "6";		break;		case "6":			dialog.text = StringFromKey("OldSmuggler_13");			link.l1 = StringFromKey("OldSmuggler_14");			link.l1.go = "7";		break;		case "7":			dialog.text = StringFromKey("OldSmuggler_15");			link.l1 = StringFromKey("OldSmuggler_16");			link.l1.go = "exit";			NextDiag.TempNode = "8";		break;		case "8":			if (CheckAttribute(pchar, "MainQuest") && pchar.MainQuest == "FL3a_s11")			{				dialog.text = StringFromKey("OldSmuggler_17");				link.l1 = StringFromKey("OldSmuggler_18");				link.l1.go = "9";				break;			}			if (CheckAttribute(pchar, "MainQuest") && pchar.MainQuest == "FL3_s15")			{				dialog.text = StringFromKey("OldSmuggler_19");				link.l1 = StringFromKey("OldSmuggler_20");				link.l1.go = "15";				break;			}			dialog.text = StringFromKey("OldSmuggler_21");			link.l1 = "...";			link.l1.go = "exit";			NextDiag.TempNode = "8";		break;		case "9":			dialog.text = StringFromKey("OldSmuggler_22");			link.l1 = StringFromKey("OldSmuggler_23");			link.l1.go = "10";		break;		case "10":			dialog.text = StringFromKey("OldSmuggler_24");			link.l1 = StringFromKey("OldSmuggler_25");			link.l1.go = "11";		break;		case "11":			dialog.text = StringFromKey("OldSmuggler_26");			link.l1 = StringFromKey("OldSmuggler_27");			link.l1.go = "12";		break;		case "12":			dialog.text = StringFromKey("OldSmuggler_28");			link.l1 = StringFromKey("OldSmuggler_29");			link.l1.go = "13";			GiveItem2Character(pchar, "FQ_letter2");		break;		case "13":			dialog.text = StringFromKey("OldSmuggler_30");			link.l1 = "...";			link.l1.go = "exit";			NextDiag.TempNode = "14";			AddDialogExitQuest("FL3a_s12");		break;		case "14":			dialog.text = StringFromKey("OldSmuggler_31");			link.l1 = "...";			link.l1.go = "exit";			NextDiag.TempNode = "14";		break;		/* -------------------------------------------------------------------- */		/* Все впорядке, сосватали */		case "15":			dialog.text = StringFromKey("OldSmuggler_32");			link.l1 = StringFromKey("OldSmuggler_33");			link.l1.go = "16";		break;		case "16":			dialog.text = StringFromKey("OldSmuggler_34");			link.l1 = StringFromKey("OldSmuggler_35");			link.l1.go = "17";		break;		case "17":			dialog.text = StringFromKey("OldSmuggler_36");			link.l1 = StringFromKey("OldSmuggler_37");			link.l1.go = "18";		break;		case "18":			dialog.text = StringFromKey("OldSmuggler_38");			link.l1 = StringFromKey("OldSmuggler_39");			link.l1.go = "19";		break;		case "19":			dialog.text = StringFromKey("OldSmuggler_40");			link.l1 = "...";			link.l1.go = "exit";			NextDiag.TempNode = "20";			AddDialogExitQuest("FL3_s16");		break;		case "20":			dialog.text = StringFromKey("OldSmuggler_41");			link.l1 = "...";			link.l1.go = "exit";			NextDiag.TempNode = "20";		break;		case "21":			dialog.text = StringFromKey("OldSmuggler_42");			link.l1 = StringFromKey("OldSmuggler_43");			link.l1.go = "22";		break;		case "22":			dialog.text = StringFromKey("OldSmuggler_44");			link.l1 = StringFromKey("OldSmuggler_45");			link.l1.go = "23";		break;		case "23":			GiveItem2Character(pchar, "spyglass3");			Log_Info(StringFromKey("InfoMessages_149"));			dialog.text = StringFromKey("OldSmuggler_46");			link.l1 = StringFromKey("OldSmuggler_47");			link.l1.go = "exit";		break;		case "exit":			if (CheckAttribute(NextDiag, "TempNode")) NextDiag.CurrentNode = NextDiag.TempNode;			DialogExit();		break;	}}